<template>
    <div class="w-100 float-left" style="overflow: auto;" id="divNodeFlowChart">
      <div v-if="flowData.length > 0" style="margin: 50px 0px; float: left; width: 3740px;" id="RflowChart">
        <RFlowChart
          :data="flowData"
          chartElement="RFlowChart"
          chartClass="tree"
          :isBillingType="isBillingType"
        />
      </div>
    </div>
  </template>
  
  <script>
  import RFlowChart from '../../../views/BillingRule/ConfigurationComponent/RFlowChart.vue';
  import DataService from "../../../services/DataService";
  
  export default {
    name: 'HorizontalFlowChart',
    components: { RFlowChart },
    props: {
      configurationId: {
        type: String,
        required: false
      },
      isBillingType: {
        type: Boolean,
        required: false
      }
    },
    data() {
      return {
        flowData: []
      };
    },
    created() {
      this.fetchRFlowData(this.configurationId);
    },
    methods: {
      async fetchRFlowData(configurationId) {
        const params = `configId=${configurationId}&includeParentNode=true&includeGlobalService=true`;
        const response = await DataService.GetNodeJsonForRule(params);
        if (response && response.data && response.data.length > 0) {
          if(this.isBillingType == true){
            this.flowData = this.buildTree(response.data);
          }
          else{
            this.flowData = this.buildTreeUtility(response.data);
          }
        }
      },
      buildTreeUtility(flatData) {
        const idMap = {};
        const topLevelNodes = [];

        // Step 1: Create a map of nodes
        flatData.forEach(item => {
            idMap[item.clientServiceMappingId] = { ...item, children: [] };
        });

        // Step 2: Attach children to parents
        flatData.forEach(item => {
            const parentId = item.parentClientServiceMappingId;
            if (parentId && idMap[parentId]) {
            idMap[parentId].children.push(idMap[item.clientServiceMappingId]);
            } else {
            topLevelNodes.push(idMap[item.clientServiceMappingId]);
            }
        });

        // Step 3: Wrap all top-level nodes under a "Start" root (only when NOT isBillingType)
        const startNode = {
            serviceId: 'start',
            serviceName: 'Start',
            nodeName: 'Start',
            isParentNode: true,
            isLeafNode: false,
            condition: '',
            children: topLevelNodes
        };

        return [startNode];
      },
      buildTree(flatData) {
          const idMap = {};
          const topLevelNodes = [];

          // Step 1: Create unique keys
          flatData.forEach((item, index) => {
              const uniqueId =
                  item.clientServiceMappingId === 0
                      ? `GLOBAL ${index}`
                      : item.clientServiceMappingId;

              idMap[uniqueId] = {
                  ...item,
                  _uid: uniqueId,
                  children: []
              };
          });

          // Step 2: Attach children correctly
          Object.values(idMap).forEach(node => {
              // GLOBAL nodes attach using parentServiceId
              if (node.clientServiceMappingId === 0) {
                  const parent = Object.values(idMap).find(
                      p => p.serviceId === node.parentServiceId
                  );

                  if (parent) {
                      parent.children.push(node);
                  } else {
                      topLevelNodes.push(node);
                  }
                  return;
              }

              // Normal nodes attach using parentClientServiceMappingId
              const parent = idMap[node.parentClientServiceMappingId];
              if (parent) {
                  parent.children.push(node);
              } else {
                  topLevelNodes.push(node);
              }
          });

          // Step 3: Sort so GLOBAL shows first
          const sortTree = nodes => {
              nodes.sort((a, b) => {
                  if (a.clientServiceMappingId === 0 && b.clientServiceMappingId !== 0) return -1;
                  if (a.clientServiceMappingId !== 0 && b.clientServiceMappingId === 0) return 1;
                  return (a.displayOrder ?? 0) - (b.displayOrder ?? 0);
              });

              nodes.forEach(n => n.children && sortTree(n.children));
          };

          sortTree(topLevelNodes);

          // Step 4: Process nodes to add display names when isBillingType is true
          if (this.isBillingType === true) {
              this.processNodeDisplayNames(topLevelNodes);
              return topLevelNodes;
          }
          
          // Wrap in Start node for non-billing type
          return [{
              serviceId: 'start',
              serviceName: 'Start',
              nodeName: 'Start',
              isLeafNode: false,
              children: topLevelNodes
          }];
      },
      processNodeDisplayNames(nodes) {
          // Process nodes at current level
          let globalCount = 0;
          let ruleCount = 0;
          
          nodes.forEach(node => {
              const isGlobal = node.clientServiceMappingId === 0 || 
                              (node.nodeName && (node.nodeName.includes('GLOBAL~') || node.nodeName.toUpperCase() === 'GLOBAL'));
              
              if (isGlobal) {
                  globalCount++;
                  node._displayName = `Global ${globalCount}`;
              } else if (node.nodeName !== '0' && node.nodeName !== 0 && 
                        node.serviceId !== 'start' && node.nodeName !== 'Start' && node.serviceName !== 'Start') {
                  ruleCount++;
                  node._displayName = `Rule ${ruleCount}`;
              } else {
                  node._displayName = '';
              }
              
              // Recursively process children
              if (node.children && node.children.length > 0) {
                  this.processNodeDisplayNames(node.children);
              }
          });
      }
    }
  };
  </script>
